const path  = require('path');
const Event = require('jibo-typed-events').Event;
const {
    StateMachine,
    State,
    TimeoutTransition,
} = require('../index');

let findRoot = require('find-root');

function timeout(ms) {
    return new Promise(res => setTimeout(res, ms));
}

const Events = {
    E1: 'E1',
    E2: 'E2',
};

describe('packages', function() {
    
    describe('jibo-state-machine', function() {

        it('loadLib', function() {
            let root = findRoot(module.filename);
            let packageStr = path.join(root, 'package.json');
            let p = require(packageStr);
            let appEntry = path.join(root, p.main);
            let lib = require(appEntry);
            expect(lib.StateMachine.name).to.equal('StateMachine');
        });

        it('Events', function() {
            let sm = new StateMachine();
            let s1 = new State(sm, 's1');
            let s2 = new State(sm, 's2');
            let bla = 1;
            s2.onEntry = (trans, result) => {
                bla = result;
            };

            s1.addEventTransition(Events.E1, s2);
            expect(sm.initial).to.be.equal(s1);
            expect(sm.current).to.not.be.ok;

            sm.start();
            expect(sm.current).to.be.equal(s1);
            expect(bla).to.be.equal(1);
            sm.emit(Events.E1, 4);
            expect(sm.current).to.be.equal(s2);
            expect(bla).to.be.equal(4);
        });

        it('Typed Events', function() {
            let sm = new StateMachine();
            let event1 = new Event('Event1');

            let s1 = new State(sm, 's1');
            let s2 = new State(sm, 's2');

            s1.addTypedEventTransition(event1, s2);
            s2.onEntry = (trans, data) => {
                expect(data).to.equal(42);
            };

            expect(sm.initial).to.be.equal(s1);
            expect(sm.current).to.not.be.ok;
            sm.start();
            expect(sm.current).to.be.equal(s1);
            event1.emit(42);
            expect(sm.current).to.be.equal(s2);
        });

        it('Timeout', function(done) {
            this.slow(400);
            let sm = new StateMachine();
            let s1 = new State(sm, 's1');
            let s2 = new State(sm, 's2');
            s1.addTransition(new TimeoutTransition('t', s2,  100));

            sm.start().catch(done);
            expect(sm.current).to.be.equal(s1);
            setTimeout(() => {
                expect(sm.current).to.be.equal(s2);
                done();
            }, 150);
        });

        it('Adding internal transitions', function () {
            let sm = new StateMachine();
            let s1 = new State(sm, 's1');
            let s2 = new State(sm, 's2');
            let s3 = new State(sm, 's3');
            // let s4 = new State(sm, 's4');

            expect(() => {
                // We can add transitions with same names to different states
                s1.addInternalTransition('', s2);
                s1.addInternalTransition('', s3);
                // And we can add transitions to the same state with different names
                s1.addInternalTransition('a', s3);
                s1.addInternalTransition('b', s3);
            }).not.to.throw();
            // Should throw on repeated adding of same
            expect(() => {
                s1.addInternalTransition('', s2);
            }).to.throw();

        });

        // Helper function for internal transition tests
        function createInternalTransitions() {
            let sm = new StateMachine();
            let s1 = new State(sm, 's1');
            let s2 = new State(sm, 's2');
            let s3 = new State(sm, 's3');
            let s4 = new State(sm, 's4');
            let done = new State(sm, 'done');
            done.onEntry = (t, data) => sm.stop(data);
            [s2, s3, s4].forEach(s => {
                s.onEntry = (t, data) => data;
                s.addDoneTransition(done);
            });
            s1.addInternalTransition('', s2);
            s1.addInternalTransition('', s3);
            s1.addInternalTransition('a', s3);
            s1.addInternalTransition('b', s3);
            return [sm, s1, s2, s3, s4];
        }

        it('Internal transition by unambiguous state', function () {
            let [sm, s1, s2] = createInternalTransitions();
            s1.onEntry = () => s1.transitionTo(s2, 'bla');
            return sm.start().then((data) => {
                expect(data).to.equal('bla');
                const trace = sm.getTrace();
                expect(trace[1].transition.name).to.equal('');
                expect(trace[1].transition.getDestinationState()).to.equal(s2);
            });
        });

        it('Internal transition by ambiguous state', function () {
            // eslint-disable-next-line no-unused-vars
            let [sm, s1, s2, s3] = createInternalTransitions();
            s1.onEntry = () => s1.transitionTo(s3, 'bla');
            return sm.start().catch(e => {
                expect(e.message.startsWith(`State 's1': has more than one matching internal transition`));
            });
        });

        it('Internal transition by unambiguous name', function () {
            // eslint-disable-next-line no-unused-vars
            let [sm, s1, s2, s3] = createInternalTransitions();
            s1.onEntry = () => s1.transitionTo('a', 'bla');
            return sm.start().then((data) => {
                expect(data).to.equal('bla');
                const trace = sm.getTrace();
                expect(trace[1].transition.name).to.equal('a');
                expect(trace[1].transition.getDestinationState()).to.equal(s3);
            });
        });
        
        it('Internal transition by ambiguous name', function () {
            // eslint-disable-next-line no-unused-vars
            let [sm, s1, s2] = createInternalTransitions();
            s1.onEntry = () => s1.transitionTo('', 'bla');
            return sm.start().catch(e => {
                expect(e.message.startsWith(`State 's1': has more than one matching internal transition`));
            });
        });

        it('Internal transition by both name and state that arent registered', function () {
            // eslint-disable-next-line no-unused-vars
            let [sm, s1, s2, s3, s4] = createInternalTransitions();
            s1.onEntry = () => s1.transitionTo('a', s4, 'bla');
            return sm.start().catch(e => {
                expect(e.message.startsWith(`State 's1': no internal transition of name 'a' to state 's4'`));
            });
        });

        it('Internal transition by both name and state', function () {
            // eslint-disable-next-line no-unused-vars
            let [sm, s1, s2, s3] = createInternalTransitions();
            s1.onEntry = () => s1.transitionTo('a', s3, 'bla');
            return sm.start().then((data) => {
                expect(data).to.equal('bla');
                const trace = sm.getTrace();
                expect(trace[1].transition.name).to.equal('a');
                expect(trace[1].transition.getDestinationState()).to.equal(s3);
            });
        });
        
        it('Immediate transition', function(done) {
            let sm = new StateMachine();
            let s1 = new State(sm, 's1');
            let s2 = new State(sm, 's2');
            let bla1 = 1;
            s1.addDoneTransition(s2);
            s1.onEntry = () => bla1 = 2;

            s2.onEntry = () => {
                expect(sm.current).to.be.equal(s2);
                expect(bla1).to.be.equal(2);
                done();
            };

            expect(bla1).to.be.equal(1);
            expect(sm.initial).to.be.equal(s1);
            sm.start().catch(done);
        });

        it('Big sequence of state transitions', function() {
            let sm = new StateMachine();
            let str = '';

            let createState = (num, last) => {
                let s = new State(sm, 's'+num);
                s.onEntry = () => str += s.name;
                if (last) {
                    last.addDoneTransition(s);
                }
                return s;
            };

            let s0 = createState(0, null);
            let s1 = createState(1, null);
            let s2 = createState(2, s1);
            let s3 = createState(3, s2);
            let s4 = createState(4, null);
            let s5 = createState(5, s4);

            s0.addEventTransition(Events.E1, s1);
            s3.addEventTransition(Events.E2, s4);

            sm.start();
            expect(sm.current).to.be.equal(s0);
            sm.emit(Events.E1);
            expect(sm.current).to.be.equal(s3);
            expect(str).to.be.equal('s0s1s2s3');
            sm.emit(Events.E2);
            expect(sm.current).to.be.equal(s5);
            expect(str).to.be.equal('s0s1s2s3s4s5');

            // Map transition trace to a state trace
            let stateTrace = sm.getTrace().map( (trans) => trans.transition.getDestinationState());
            expect(stateTrace).to.deep.equal([s0, s1, s2, s3, s4, s5]);
        });

        it('Loop detection', function(done) {
            let sm = new StateMachine();
            let s1 = new State(sm, 's1');
            let s2 = new State(sm, 's2');
            let s3 = new State(sm, 's3');
            s1.addDoneTransition(s2);
            s2.addDoneTransition(s3);
            s3.addDoneTransition(s1);

            sm.start().catch(e => {
                expect(e.message.startsWith("State machine has looped")).to.be.true;
                done();
            });
        });

        it('Asynchronous exit method', function(done) {
            let arr = [];
            let sm = new StateMachine();
            let s1 = new State(sm, 's1');
            let s2 = new State(sm, 's2');
            let s3 = new State(sm, 's3');
            s1.addEventTransition('event', s2);
            s2.addDoneTransition(s3);

            s1.onEntry = () => arr.push('s1-entry');
            s1.onExit = () => arr.push('s1-exit');
            s2.onEntry = () => arr.push('s2-entry');
            s2.onExit = () => {
                arr.push('s2-exit');
                return timeout(10).then(() => {
                    arr.push('s2-post-exit');
                });
            };

            s3.onEntry = () => {
                expect(arr).to.deep.equal(['s1-entry', 's1-exit', 's2-entry', 's2-exit', 's2-post-exit']);
                done();
            };

            sm.start().catch(done);
            sm.emit('event');
        });

        it('stop 1', function(done) {
            this.slow(400);
            let sm = new StateMachine();
            let s1 = new State(sm, 's1');
            let s2 = new State(sm, 's2');
            s1.addDoneTransition(s2);

            let arr = [];
            s1.onEntry = () => arr.push('s1-entry');
            s1.onExit = () => arr.push('s1-exit');
            s1.onStop = () => arr.push('s1-stop');
            s2.onEntry = () => arr.push('s2-entry');
            s2.onExit = () => arr.push('s2-exit');
            s2.onStop = () => arr.push('s2-stop');

            sm.start().catch(done);
            sm.stop().then(() => {
                expect(sm.current).to.be.equal(null);
                expect(arr).to.deep.equal(['s1-entry', 's1-exit', 's2-entry','s2-stop', 's2-exit']);
                done();
            }).catch(done);
        });

        it('stop 2', function(done) {
            this.slow(400);
            let sm = new StateMachine();
            let s1 = new State(sm, 's1');
            let s2 = new State(sm, 's2');
            s1.addDoneTransition(s2);

            let arr = [];
            s1.onEntry = () => arr.push('s1-entry');
            s1.onExit = () => arr.push('s1-exit');
            s1.onStop = () => arr.push('s1-stop');
            s2.onEntry = () => arr.push('s2-entry');
            s2.onExit = () => arr.push('s2-exit');
            s2.onStop = () => arr.push('s2-stop');

            sm.start().catch(done);
            sm.stop().then(() => {
                expect(sm.current).to.be.equal(null);
                expect(arr).to.deep.equal(['s1-entry', 's1-exit', 's2-entry', 's2-stop', 's2-exit']);
                done();
            }).catch(done);
        });
        
        
        it('calling stop before start', function(done) {
            this.slow(400);
            let sm = new StateMachine();
            let s1 = new State(sm, 's1');
            let s2 = new State(sm, 's2');
            s1.addDoneTransition(s2);
            
            let arr = [];
            s1.onEntry = () => arr.push('s1-entry');
            s1.onExit = () => arr.push('s1-exit');
            s1.onStop = () => arr.push('s1-stop');
            s2.onEntry = () => arr.push('s2-entry');
            s2.onExit = () => arr.push('s2-exit');
            s2.onStop = () => arr.push('s2-stop');
            
            sm.stop().then(() => {
                expect(sm.current).to.not.be.ok;
                expect(arr).to.deep.equal([]);
                done();
            }).catch(done);
        });

        it('stop with event transition', function(done) {
            let sm = new StateMachine();
            let s1 = new State(sm, 's1');
            let s2 = new State(sm, 's2');
            s1.addEventTransition('event', s2);
            let s2WasEntered = false;
            s2.onEntry = () => {
                s2WasEntered = true;
            };

            sm.start().catch(done);
            sm.stop().then(() => {
                sm.emit('event');
                expect(sm.current).to.be.equal(null);
                expect(s2WasEntered).to.be.equal(false);
                done();
            }).catch(done);
        });

        it('update', function() {
            let sm = new StateMachine();
            let s1 = new State(sm, 's1');
            let s1WasUpdated = false;
            s1.onUpdate = () => {
                s1WasUpdated = true;
            };

            sm.start();
            sm.update();
            expect(sm.current).to.be.equal(s1);
            expect(s1WasUpdated).to.be.equal(true, 's1 did not have stop called!');
        });


        it('destroy', function(done) {
            let sm = new StateMachine();
            let s1 = new State(sm, 's1');
            let s2 = new State(sm, 's2');
            s1.addDoneTransition(s2);

            let arr = [];
            s1.onEntry = () => arr.push('s1-entry');
            s1.onExit = () => arr.push('s1-exit');
            s1.onStop = () => arr.push('s1-stop');
            s2.onEntry = () => arr.push('s2-entry');
            s2.onExit = () => arr.push('s2-exit');
            s2.onStop = () => arr.push('s2-stop');

            sm.start().catch(done);
            sm.destroy().then(() => {
                expect(arr).to.deep.equal(['s1-entry', 's1-exit', 's2-entry', 's2-stop', 's2-exit']);
                done();
            }).catch(done);
        });

        it('Done transitions', function(done) {
            let sm = new StateMachine();
            let s1 = new State(sm, 's1');
            let s2 = new State(sm, 's2');
            let s3 = new State(sm, 's3');

            s1.addDoneTransition(s2);
            s2.addDoneTransition(s3);

            s1.onEntry = () => {
                return timeout(10).then(() => 'test');
            };

            s2.onEntry = (trans, data) => {
                expect(data).to.equal('test');
                return 'test2';
            };

            s3.onEntry = (trans, data) => {
                expect(data).to.equal('test2');
                done();
            };

            sm.start().catch(done);
        });

        it('Done transitions (happening after leaving state)', function(done) {
            let sm = new StateMachine();
            let s1 = new State(sm, 's1');
            let s2 = new State(sm, 's2');

            s1.addDoneTransition(s2);
            s1.addEventTransition('test', s2);

            s2.onEntry = (trans, data) => {
                expect(data).to.equal('bla');
                done();
            };

            s1.onEntry = () => {
                return timeout(10).then(() => 'done');
            };

            sm.start().catch(done);
            sm.emit('test', 'bla');
        });

        it('Done transitions (failed)', function(done) {
            let sm = new StateMachine(err => {
                expect(err.message).equal("Error in state 's1': error");
                done();
            });

            let s1 = new State(sm, 's1');
            let s2 = new State(sm, 's2');

            s1.addDoneTransition(s2);

            s1.onEntry = () => {
                return timeout(10).then(() => {
                    return Promise.reject('error')
                });
            };

            sm.start().catch(e => {
                expect(e).to.equal('error');
                done();
            });
        });

        it('Error in state', function(done) {
            let sm = new StateMachine();

            let s1 = new State(sm, 's1');
            s1.onEntry = () => {
                throw new Error('error');
            };

            sm.start().catch(err => {
                expect(err.message).equal("error");
                done();
            });
        });

        it('State machine stopping', function(done) {
            let sm = new StateMachine();
            let s1 = new State(sm, 's1');
            let s2 = new State(sm, 's2');
            let s3 = new State(sm, 's3');

            s1.addDoneTransition(s2);
            s2.addDoneTransition(s3);

            s2.onEntry = () => {
                sm.stop('data2');
            };

            s3.onEntry = () => {
                sm.stop('data3');
            };

            sm.start().then(data => {
                expect(sm.getCurrentState()).to.equal(null);
                expect(data).to.equal("data2");
                done();
            }).catch(done);
        });

        it('Restarting state machine', function(done) {
            let sm = new StateMachine();
            let s1 = new State(sm, 's1');
            let s2 = new State(sm, 's2');
            let s3 = new State(sm, 's3');

            s1.addDoneTransition(s2);
            s2.addDoneTransition(s3);

            let str = '';

            s1.onEntry = () => str += 's1';
            s2.onEntry = () => str += 's2';
            s3.onEntry = () => {
                str += 's3';
                sm.stop(str);
            };

            sm.start()
                .then(data => {
                    expect(sm.getCurrentState()).to.equal(null);
                    expect(data).to.equal("s1s2s3");
                    return sm.start();
                }).then(data => {
                    expect(sm.getCurrentState()).to.equal(null);
                    expect(data).to.equal("s1s2s3s1s2s3");
                    done();
                }).catch(done);
        });
        
        
        it('Restarting start right after a stop', function(done) {
            let sm = new StateMachine();
            let s1 = new State(sm, 's1');
            let s2 = new State(sm, 's2');
            let s3 = new State(sm, 's3');
            
            s1.addDoneTransition(s2);
            s2.addDoneTransition(s3);
            
            let str = '';
            
            s1.onEntry = () => {
                str += 's1';
                return timeout(10);
            };
            s2.onEntry = () => {
                str += 's2';
                return timeout(10);
            };
            s3.onEntry = () => {
                str += 's3';
                sm.stop(str);
            };
            
            sm.start().catch(done);
            
            process.nextTick(() => {
                sm.stop().then((data) => {
                    expect(data).to.not.be.ok;
                    expect(str).to.equal("s1");
                    return sm.start();
                }).then(data => {
                    expect(data).to.equal("s1s1s2s3");
                    done();
                })
            });
        });
        
        it('Calling start again before state machine is done', function(done) {
            let sm = new StateMachine();
            let s1 = new State(sm, 's1');
            let s2 = new State(sm, 's2');
            let s3 = new State(sm, 's3');
            
            let caughtError = false;
            
            sm.once('inState2', () => {
                expect(arr).to.deep.equal(['s1', 's2']);
                sm.start().catch(err => {
                    expect(err.message.startsWith('State machine already running')).to.be.ok;
                    caughtError = true;
                });
            });
            
            s1.addDoneTransition(s2);
            s2.addDoneTransition(s3);
            
            
            let arr = [];
            s1.onEntry = () => {
                arr.push('s1');
                return timeout(10);
            };
            s1.onExit = () => timeout(10);
            s2.onEntry = () => {
                arr.push('s2');
                sm.emit('inState2');
                return timeout(10);
            };
            s2.onExit = () => timeout(10);
            s3.onEntry = () => {
                arr.push('s3');
                sm.stop(arr);
            };
            s3.onExit = () => timeout(10);
            
            sm.start().then(data => {
                expect(data).to.deep.equal(['s1', 's2', 's3']);
                expect(caughtError).to.be.ok;
                done();
            }).catch(done);
        });
        
        it('Get trace', function(done) {
            let sm = new StateMachine();
            let s1 = new State(sm, 's1');
            let s2 = new State(sm, 's2');
            let s3 = new State(sm, 's3');
            
            s1.addDoneTransition(s2);
            s2.addDoneTransition(s3);

            s3.onEntry = () => {
                sm.stop();
            };
            
            let count = 0;
            s2.onEntry = () => {
                const t = sm.getTrace();
                expect(t.length).to.equal(2);
                count++;
            };
        
            sm.start().then(() => {
                expect(sm.getTrace().length).to.equal(3);
                expect(count).to.equal(1);
                return sm.start();
            }).then(() => {
                const trace = sm.getTrace();
                expect(trace.length).to.equal(3);
                expect(trace[0].timestamp).to.be.a('number');
                expect(trace[0].transition).to.be.a('object');
                expect(count).to.equal(2);
                done();
            }).catch(done);
        });

        it('Rapid restarts', function(done) {
            let sm = new StateMachine();
            let s1 = new State(sm, 's1');
            let s2 = new State(sm, 's2');
            
            s1.addDoneTransition(s2);

            s1.onEntry = () => {
                return timeout(50);
            };
            s1.onStop = () => {
                return timeout(50);
            };

            s2.onEntry = () => {
                sm.stop();
            };
            
            let pr = sm.start();
            for (let i=0; i<10; i++) {
                pr = pr.then(() => {
                    // We always wait for the stop
                    return sm.stop();
                }).then(() => {
                    // We don't wait for the start
                    sm.start();
                });
            }
            
            pr.then(() => {
                done();
            }).catch(done);
        });

        it('State machine transition events', function (done) {
            let sm = new StateMachine();
            let arr = [];
            sm.stateChanged.on(t => arr.push(t.getDestinationState()));
            let s1 = new State(sm, 's1');
            let s2 = new State(sm, 's2');
            let s3 = new State(sm, 's3');
            s1.addDoneTransition(s2);
            s2.addDoneTransition(s3);
            s3.onEntry = () => {
                expect(arr).to.deep.equal([s1, s2, s3]);
                done();
            };
            sm.start().catch(done);
        });

        it('Make sure exit completes when stopping', function (done) {
            let sm = new StateMachine();
            let arr = [];
            let s1 = new State(sm, 's1');
            let s2 = new State(sm, 's2');
            s1.addDoneTransition(s2);
            
            s1.onStop = () => {
                arr.push(2);
                return new Promise(resolve => setTimeout(resolve, 5))
                    .then(() => {
                        arr.push(3);
                    })
            };

            s1.onExit = () => {
                arr.push(1);
                return new Promise(resolve => setTimeout(resolve, 10))
                    .then(() => {
                        arr.push(4);
                    })
            };
            sm.start().then(() => {
                expect(arr).to.deep.equal([1, 2, 3, 4]);
                done();
            }).catch(done);
            sm.stop();
        });

        it('Transitioning out of inactive state (when sm is running)', function (done) {
            let sm = new StateMachine();
            let s1 = new State(sm, 's1');
            let s2 = new State(sm, 's2');
            s2.addInternalTransition('', s1);

            let log = State.prototype.log;
            // We expect to get the following log warning
            sinon.stub(log, 'warn', (message) => {
                log.warn.restore();
                expect(message).to.equal("Attempting internal transition out of a non-current state. This state: 's2', target state: 's1', transition name: ''. Current state: 's1'.");
                done();
            });

            sm.start();
            s2.transitionTo(s1); // Here we try to transition out of a non-active state 
        });

        it('Transitioning out of inactive state (when sm is not running)', function (done) {
            let sm = new StateMachine();
            let s1 = new State(sm, 's1');
            let s2 = new State(sm, 's2');
            s1.onEntry = () => sm.stop();
            s2.addInternalTransition('', s1);

            let log = State.prototype.log;

            // We expect to get the following log warning
            sinon.stub(log, 'warn', (message) => {
                log.warn.restore();
                expect(message).to.equal("Attempting internal transition out of a non-current state. This state: 's2', target state: 's1', transition name: ''. The state machine is currently not running.");
                done();
            });

            sm.start().then(() => {
                s2.transitionTo(s1); // Here we try to transition out of a non-active state 
            });
        });
    });

});